const config = $('CONFIG').item.json;
const data = $input.first().json;

if (!data.success || !Array.isArray(data.proposals)) {
  console.log('No se pudieron obtener propuestas:', data.error || 'unknown');
  return [];
}

const headers = {
  'apikey': config.SUPABASE_KEY,
  'Authorization': `Bearer ${config.SUPABASE_KEY}`,
  'Content-Type': 'application/json',
};

let updated = 0;
for (const p of data.proposals) {
  if (!p.project_url) continue;

  const body = {
    client_responded: p.client_responded || false,
  };

  // Solo actualizar outcome si no es 'in_progress' (no sobreescribir won/lost)
  if (p.outcome && p.outcome !== 'in_progress') {
    body.outcome = p.outcome;
    if (p.outcome === 'won') body.status = 'won';
    else if (p.outcome === 'lost') body.status = 'lost';
  }

  try {
    await fetch(
      `${config.SUPABASE_URL}/rest/v1/workana_projects?workana_url=eq.${encodeURIComponent(p.project_url)}`,
      { method: 'PATCH', headers, body: JSON.stringify(body) }
    );
    updated++;
  } catch (e) {
    console.error('Error actualizando:', p.project_url, e.message);
  }
}

console.log(`Actualizados ${updated}/${data.proposals.length} proyectos`);
return [{ json: { updated, total: data.proposals.length } }];
